package com.wotb.web.boost.controller;

import com.wotb.web.boost.dto.AssignBoosterRequest;
import com.wotb.web.boost.dto.BoostAssignmentDto;
import com.wotb.web.boost.dto.UnassignBoosterRequest;
import com.wotb.web.boost.entity.BoostRequest;
import com.wotb.web.boost.service.AdminBoostRequestService;
import com.wotb.web.boost.service.BoostAssignmentService;
import com.wotb.web.boost.service.BoostRequestService;
import org.springframework.context.annotation.Profile;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.CrossOrigin;
import org.springframework.web.bind.annotation.PatchMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ResponseStatusException;

import java.util.Map;

/** 管理员侧分配接口。 */
@RestController
@RequestMapping("/api/admin/boost/requests/{id}/assignments")
@CrossOrigin(origins = "*")
@Profile("postgres")
public class AdminBoostAssignmentController {

    private final BoostAssignmentService assignmentService;
    private final BoostRequestService requestService;
    private final AdminBoostRequestService adminRequestService;

    public AdminBoostAssignmentController(final BoostAssignmentService assignmentService,
                                          final BoostRequestService requestService,
                                          final AdminBoostRequestService adminRequestService) {
        this.assignmentService = assignmentService;
        this.requestService = requestService;
        this.adminRequestService = adminRequestService;
    }

    /** 分配打手。 */
    @PostMapping
    public BoostAssignmentDto assign(@PathVariable final Long id,
                                     @RequestBody final AssignBoosterRequest body) {
        try {
            final BoostAssignmentDto dto = assignmentService.assign(id, body.boosterId(), body.note());
            // 更新需求状态为 MATCHED
            adminRequestService.updateStatus(id, "MATCHED", null);
            return dto;
        } catch (final DataIntegrityViolationException e) {
            throw new ResponseStatusException(HttpStatus.CONFLICT, "ACTIVE_ASSIGNMENT_EXISTS");
        } catch (final IllegalArgumentException | IllegalStateException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }

    /** 取消当前分配。 */
    @PatchMapping("/current/unassign")
    public Map<String, Object> unassign(@PathVariable final Long id,
                                        @RequestBody final UnassignBoosterRequest body) {
        try {
            final BoostAssignmentDto dto = assignmentService.unassign(id, body.note());
            // 如果需求状态为 MATCHED，改回 REVIEWING
            final BoostRequest req = requestService.getById(id);
            if ("MATCHED".equalsIgnoreCase(req.getStatus())) {
                adminRequestService.updateStatus(id, "REVIEWING", null);
            }
            return Map.of(
                    "id", dto.id(),
                    "requestId", dto.requestId(),
                    "status", dto.status(),
                    "statusLabel", dto.statusLabel(),
                    "unassignedAt", dto.unassignedAt(),
                    "message", "当前分配已取消。"
            );
        } catch (final IllegalArgumentException | IllegalStateException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }
}

package com.wotb.web.boost.controller;

import com.wotb.web.boost.dto.BoosterDto;
import com.wotb.web.boost.dto.CreateBoosterRequest;
import com.wotb.web.boost.dto.UpdateBoosterAvailabilityRequest;
import com.wotb.web.boost.dto.UpdateBoosterRequest;
import com.wotb.web.boost.service.BoosterService;
import org.springframework.context.annotation.Profile;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.CrossOrigin;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PatchMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ResponseStatusException;

import java.util.Map;

/** 管理员侧打手管理接口。 */
@RestController
@RequestMapping("/api/admin/boost/boosters")
@CrossOrigin(origins = "*")
@Profile("postgres")
public class AdminBoosterController {

    private final BoosterService service;

    public AdminBoosterController(final BoosterService service) {
        this.service = service;
    }

    @PostMapping
    public BoosterDto create(@RequestBody final CreateBoosterRequest body) {
        try {
            return service.create(
                    body.nickname(), body.level(), body.available(), body.status(),
                    body.contactType(), body.contactValue(),
                    body.specialties(), body.description()
            );
        } catch (final IllegalArgumentException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }

    @GetMapping
    public Page<BoosterDto> list(
            @RequestParam(name = "status", required = false) final String status,
            @RequestParam(name = "available", required = false) final Boolean available,
            @RequestParam(name = "page", defaultValue = "0") final int page,
            @RequestParam(name = "size", defaultValue = "20") final int size) {
        return service.list(status, available, PageRequest.of(page, size));
    }

    @GetMapping("/{id}")
    public BoosterDto get(@PathVariable final Long id) {
        try {
            return service.getDto(id);
        } catch (final IllegalArgumentException e) {
            throw new ResponseStatusException(HttpStatus.NOT_FOUND, "打手不存在");
        }
    }

    @PatchMapping("/{id}")
    public BoosterDto update(@PathVariable final Long id,
                             @RequestBody final UpdateBoosterRequest body) {
        try {
            return service.update(
                    id, body.nickname(), body.level(), body.available(), body.status(),
                    body.contactType(), body.contactValue(),
                    body.specialties(), body.description()
            );
        } catch (final IllegalArgumentException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }

    @PatchMapping("/{id}/availability")
    public Map<String, Object> setAvailability(@PathVariable final Long id,
                                               @RequestBody final UpdateBoosterAvailabilityRequest body) {
        try {
            final BoosterDto dto = service.setAvailability(id, body.available());
            return Map.of("id", dto.id(), "available", dto.available(), "updatedAt", dto.updatedAt());
        } catch (final IllegalArgumentException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }
}

package com.wotb.web.boost.controller;

import com.wotb.web.boost.dto.AdminBoostRequestDto;
import com.wotb.web.boost.dto.UpdateBoostRequestStatusRequest;
import com.wotb.web.boost.service.AdminBoostRequestService;
import org.springframework.context.annotation.Profile;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.CrossOrigin;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PatchMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestBody;
