            final AdminBoostRequestDto dto = service.updateStatus(id, body.status(), body.adminNote());
            return Map.of(
                    "id", dto.id(),
                    "status", dto.status(),
                    "statusLabel", dto.statusLabel(),
                    "adminNote", dto.adminNote() != null ? dto.adminNote() : "",
                    "updatedAt", dto.updatedAt()
            );
        } catch (final IllegalArgumentException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }
}

package com.wotb.web.boost.controller;

import com.wotb.web.boost.dto.BoostRequestDto;
import com.wotb.web.boost.dto.CreateBoostRequestRequest;
import com.wotb.web.boost.dto.CreateBoostRequestResponse;
import com.wotb.web.boost.service.BoostRequestService;
import com.wotb.web.boost.util.JwtUtil;
import org.springframework.context.annotation.Profile;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.CrossOrigin;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PatchMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ResponseStatusException;

import java.util.List;
import java.util.Map;

/** 玩家侧需求接口 — 需登录。 */
@RestController
@RequestMapping("/api/boost/requests")
@CrossOrigin(origins = "*")
@Profile("postgres")
public class BoostRequestController {

    private final BoostRequestService service;

    public BoostRequestController(final BoostRequestService service) {
        this.service = service;
    }

    /** 创建陪练需求。 */
    @PostMapping
    public CreateBoostRequestResponse create(@RequestBody final CreateBoostRequestRequest body) {
        final String userId = requireUserId();
        try {
            return service.create(
                    userId,
                    body.region(),
                    body.requestType(),
                    body.targetDescription(),
                    body.contactType(),
                    body.contactValue(),
                    body.playerAccountId(),
                    body.playerNickname(),
                    body.budgetRange(),
                    body.availableTime(),
                    body.remark()
            );
        } catch (final IllegalArgumentException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }

    /** 查看我的需求。 */
    @GetMapping("/my")
    public List<BoostRequestDto> listMy() {
        return service.listMy(requireUserId());
    }

    /** 查看我的单个需求。 */
    @GetMapping("/my/{id}")
    public BoostRequestDto getMy(@PathVariable final Long id) {
        return service.getMy(id, requireUserId())
                .orElseThrow(() -> new ResponseStatusException(HttpStatus.NOT_FOUND, "需求不存在"));
    }

    /** 取消我的需求。 */
    @PatchMapping("/my/{id}/cancel")
    public Map<String, Object> cancel(@PathVariable final Long id) {
        final String userId = requireUserId();
        try {
            final BoostRequestDto dto = service.cancel(id, userId);
            return Map.of(
                    "id", dto.id(),
                    "status", dto.status(),
                    "statusLabel", dto.statusLabel(),
                    "message", "需求已取消。"
            );
        } catch (final IllegalArgumentException e) {
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage());
        }
    }

    private static String requireUserId() {
        final String userId = JwtUtil.currentUserId();
        if (userId == null) {
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, "请先登录");
        }
        return userId;
    }
}

package com.wotb.web.boost.service;

import com.wotb.web.boost.dto.AdminBoostRequestDto;
import com.wotb.web.boost.dto.BoostAssignmentDto;
import com.wotb.web.boost.dto.BoosterSummaryDto;
import com.wotb.web.boost.entity.BoostRequest;
import com.wotb.web.boost.entity.BoostRequestAssignment;
import com.wotb.web.boost.entity.BoosterProfile;
import com.wotb.web.boost.enums.BoostAssignmentStatus;
import com.wotb.web.boost.enums.BoostRegion;
import com.wotb.web.boost.enums.BoostRequestStatus;
import com.wotb.web.boost.enums.BoostRequestType;
import com.wotb.web.boost.enums.BoosterLevel;
import com.wotb.web.boost.enums.BoosterStatus;
import com.wotb.web.boost.repository.BoostRequestAssignmentRepository;
import com.wotb.web.boost.repository.BoostRequestRepository;
import com.wotb.web.boost.repository.BoosterProfileRepository;
import org.springframework.context.annotation.Profile;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.OffsetDateTime;
import java.util.Optional;

/** 管理员侧需求服务。 */
@Service
@Profile("postgres")
public class AdminBoostRequestService {

    private final BoostRequestRepository repository;
    private final BoostRequestAssignmentRepository assignmentRepository;
    private final BoosterProfileRepository boosterRepository;

    public AdminBoostRequestService(final BoostRequestRepository repository,
                                    final BoostRequestAssignmentRepository assignmentRepository,
                                    final BoosterProfileRepository boosterRepository) {
        this.repository = repository;
        this.assignmentRepository = assignmentRepository;
        this.boosterRepository = boosterRepository;
    }

    public Page<AdminBoostRequestDto> list(final String status, final Pageable pageable) {
        final Page<BoostRequest> page;
        if (status != null && !status.isBlank()) {
            page = repository.findByStatus(status, pageable);
        } else {
            page = repository.findAll(pageable);
        }
        return page.map(this::toAdminDto);
    }

    public Optional<AdminBoostRequestDto> get(final Long id) {
        return repository.findById(id).map(this::toAdminDto);
    }

    @Transactional
    public AdminBoostRequestDto updateStatus(final Long id, final String status, final String adminNote) {
        final BoostRequest req = repository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("REQUEST_NOT_FOUND"));

        BoostRequestStatus.from(status);

        req.setStatus(status.toUpperCase());
        if (adminNote != null) {
            req.setAdminNote(adminNote);
        }
        req.setUpdatedAt(OffsetDateTime.now());

        repository.save(req);
        return toAdminDto(req);
    }

    private AdminBoostRequestDto toAdminDto(final BoostRequest req) {
        final Optional<BoostRequestAssignment> active = assignmentRepository
                .findByRequestIdAndUnassignedAtIsNull(req.getId());

        BoostAssignmentDto current = null;
        if (active.isPresent()) {
            final BoostRequestAssignment a = active.get();
            final BoosterProfile b = boosterRepository.findById(a.getBoosterId()).orElse(null);
            if (b != null) {
                current = new BoostAssignmentDto(
                        a.getId(),
                        a.getRequestId(),
                        new BoosterSummaryDto(
                                b.getId(),
                                b.getNickname(),
                                b.getLevel(),
                                BoosterLevel.from(b.getLevel()).label(),
                                b.getAvailable(),
                                b.getStatus(),
                                BoosterStatus.from(b.getStatus()).label()
                        ),
                        a.getStatus(),
                        BoostAssignmentStatus.from(a.getStatus()).label(),
                        a.getAssignedAt(),
                        a.getUnassignedAt(),
                        a.getNote(),
                        a.getCreatedAt(),
                        a.getUpdatedAt()
                );
            }
        }

        return new AdminBoostRequestDto(
                req.getId(),
                req.getRequesterUserId(),
                req.getWotbAccountId(),
                req.getPlayerAccountId(),
                req.getPlayerNickname(),
                req.getRegion(),
                BoostRegion.from(req.getRegion()).label(),
                req.getRequestType(),
                BoostRequestType.from(req.getRequestType()).label(),
                req.getTargetDescription(),
                req.getBudgetRange(),
                req.getContactType(),
                req.getContactValue(),
                req.getAvailableTime(),
                req.getRemark(),
                req.getStatus(),
                BoostRequestStatus.from(req.getStatus()).label(),
                req.getAdminNote(),
                current,
                req.getCreatedAt(),
                req.getUpdatedAt()
        );
    }
}

package com.wotb.web.boost.service;

import com.wotb.web.boost.dto.BoostAssignmentDto;
import com.wotb.web.boost.dto.BoosterSummaryDto;
import com.wotb.web.boost.entity.BoostRequestAssignment;
import com.wotb.web.boost.entity.BoosterProfile;
import com.wotb.web.boost.enums.BoostAssignmentStatus;
import com.wotb.web.boost.enums.BoosterLevel;
import com.wotb.web.boost.enums.BoosterStatus;
import com.wotb.web.boost.repository.BoostRequestAssignmentRepository;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.OffsetDateTime;
import java.util.Optional;

/** 分配服务。 */
@Service
@Profile("postgres")
public class BoostAssignmentService {

    private final BoostRequestAssignmentRepository assignmentRepository;
    private final BoosterService boosterService;

    public BoostAssignmentService(final BoostRequestAssignmentRepository assignmentRepository,
                                  final BoosterService boosterService) {
        this.assignmentRepository = assignmentRepository;
        this.boosterService = boosterService;
    }

    /** 查找当前活跃分配（unassigned_at is null）。 */
    public Optional<BoostRequestAssignment> findActive(final Long requestId) {
        return assignmentRepository.findByRequestIdAndUnassignedAtIsNull(requestId);
    }

    /** 分配打手给需求。 */
    @Transactional
    public BoostAssignmentDto assign(final Long requestId, final Long boosterId, final String note) {
        // 检查是否已有活跃分配
        if (assignmentRepository.findByRequestIdAndUnassignedAtIsNull(requestId).isPresent()) {
            throw new IllegalStateException("ACTIVE_ASSIGNMENT_EXISTS");
        }

        final BoosterProfile booster = boosterService.getById(boosterId);
        if (!"ACTIVE".equalsIgnoreCase(booster.getStatus())) {
            throw new IllegalArgumentException("BOOSTER_NOT_AVAILABLE");
        }

        final BoostRequestAssignment assignment = new BoostRequestAssignment();
        assignment.setRequestId(requestId);
        assignment.setBoosterId(boosterId);
        assignment.setStatus(BoostAssignmentStatus.ASSIGNED.name());
        assignment.setAssignedAt(OffsetDateTime.now());
        assignment.setNote(note);

        assignmentRepository.save(assignment);

        return toDto(assignment, booster);
    }

    /** 取消当前活跃分配。 */
    @Transactional
    public BoostAssignmentDto unassign(final Long requestId, final String note) {
        final BoostRequestAssignment assignment = assignmentRepository
                .findByRequestIdAndUnassignedAtIsNull(requestId)
                .orElseThrow(() -> new IllegalStateException("NO_ACTIVE_ASSIGNMENT"));

        final OffsetDateTime now = OffsetDateTime.now();
        assignment.setUnassignedAt(now);
        assignment.setStatus(BoostAssignmentStatus.CANCELLED.name());
        assignment.setNote(note);
        assignment.setUpdatedAt(now);

        assignmentRepository.save(assignment);

        final BoosterProfile booster = boosterService.getById(assignment.getBoosterId());
        return toDto(assignment, booster);
    }

    /** 统计某打手当前活跃分配数。 */
    public long activeCount(final Long boosterId) {
        return assignmentRepository.countByBoosterIdAndUnassignedAtIsNull(boosterId);
    }

    static BoostAssignmentDto toDto(final BoostRequestAssignment a, final BoosterProfile b) {
        return new BoostAssignmentDto(
                a.getId(),
                a.getRequestId(),
                new BoosterSummaryDto(
                        b.getId(),
                        b.getNickname(),
                        b.getLevel(),
                        BoosterLevel.from(b.getLevel()).label(),
                        b.getAvailable(),
                        b.getStatus(),
                        BoosterStatus.from(b.getStatus()).label()
                ),
                a.getStatus(),
                BoostAssignmentStatus.from(a.getStatus()).label(),
                a.getAssignedAt(),
                a.getUnassignedAt(),
                a.getNote(),
                a.getCreatedAt(),
                a.getUpdatedAt()
        );
    }
}

package com.wotb.web.boost.service;

import com.wotb.web.boost.dto.BoosterDto;
import com.wotb.web.boost.entity.BoosterProfile;
import com.wotb.web.boost.enums.BoosterLevel;
import com.wotb.web.boost.enums.BoosterStatus;
import com.wotb.web.boost.enums.ContactType;
import com.wotb.web.boost.repository.BoostRequestAssignmentRepository;
import com.wotb.web.boost.repository.BoosterProfileRepository;
import org.springframework.context.annotation.Profile;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.OffsetDateTime;

/** 打手管理服务。 */
@Service
@Profile("postgres")
public class BoosterService {

    private final BoosterProfileRepository repository;
    private final BoostRequestAssignmentRepository assignmentRepository;

    public BoosterService(final BoosterProfileRepository repository,
                          final BoostRequestAssignmentRepository assignmentRepository) {
        this.repository = repository;
        this.assignmentRepository = assignmentRepository;
    }

    public BoosterProfile getById(final Long id) {
        return repository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("BOOSTER_NOT_FOUND"));
    }

    @Transactional
    public BoosterDto create(final String nickname, final String level,
                             final Boolean available, final String status,
                             final String contactType, final String contactValue,
                             final String specialties, final String description) {
        if (nickname == null || nickname.isBlank()) {
            throw new IllegalArgumentException("打手昵称不能为空");
        }
        if (level == null) {
            throw new IllegalArgumentException("打手等级不能为空");
        }
        BoosterLevel.from(level);

        final BoosterProfile p = new BoosterProfile();
        p.setNickname(nickname.trim());
        p.setLevel(level.toUpperCase());
        p.setAvailable(available != null ? available : true);
        p.setStatus(status != null ? status.toUpperCase() : BoosterStatus.ACTIVE.name());
        if (contactType != null && !contactType.isBlank()) {
            ContactType.from(contactType);
            p.setContactType(contactType.toUpperCase());
        }
        p.setContactValue(contactValue);
        p.setSpecialties(specialties);
        p.setDescription(description);

        repository.save(p);
        return toDto(p);
    }

    @Transactional
    public BoosterDto update(final Long id, final String nickname, final String level,
                             final Boolean available, final String status,
                             final String contactType, final String contactValue,
                             final String specialties, final String description) {
        final BoosterProfile p = getById(id);

        if (nickname != null) { p.setNickname(nickname.trim()); }
        if (level != null) {
            BoosterLevel.from(level);
            p.setLevel(level.toUpperCase());
        }
        if (available != null) { p.setAvailable(available); }
        if (status != null) {
            BoosterStatus.from(status);
            p.setStatus(status.toUpperCase());
        }
        if (contactType != null) {
            ContactType.from(contactType);
            p.setContactType(contactType.toUpperCase());
        }
        if (contactValue != null) { p.setContactValue(contactValue); }
        if (specialties != null) { p.setSpecialties(specialties); }
        if (description != null) { p.setDescription(description); }
        p.setUpdatedAt(OffsetDateTime.now());

        repository.save(p);
        return toDto(p);
    }

    @Transactional
    public BoosterDto setAvailability(final Long id, final Boolean available) {
        final BoosterProfile p = getById(id);
        p.setAvailable(available);
        p.setUpdatedAt(OffsetDateTime.now());
        repository.save(p);
        return toDto(p);
    }

    public BoosterDto getDto(final Long id) {
        return toDto(getById(id));
    }

    public Page<BoosterDto> list(final String status, final Boolean available,
                                 final Pageable pageable) {
        Page<BoosterProfile> page;
        if (status != null && !status.isBlank() && available != null) {
            page = repository.findByStatusAndAvailable(status, available, pageable);
        } else if (status != null && !status.isBlank()) {
            page = repository.findByStatus(status, pageable);
        } else if (available != null) {
            page = repository.findByAvailable(available, pageable);
        } else {
            page = repository.findAll(pageable);
        }
        return page.map(this::toDto);
    }

    private BoosterDto toDto(final BoosterProfile p) {
        return new BoosterDto(
                p.getId(),
                p.getNickname(),
                p.getLevel(),
                BoosterLevel.from(p.getLevel()).label(),
                p.getAvailable(),
                p.getStatus(),
                BoosterStatus.from(p.getStatus()).label(),
                p.getContactType(),
                p.getContactValue(),
                p.getSpecialties(),
                p.getDescription(),
                (int) assignmentRepository.countByBoosterIdAndUnassignedAtIsNull(p.getId()),
                p.getCreatedAt(),
                p.getUpdatedAt()
        );
    }
}

package com.wotb.web.boost.service;

import com.wotb.web.boost.dto.BoostAssignmentDto;
import com.wotb.web.boost.dto.BoostRequestDto;
import com.wotb.web.boost.dto.CreateBoostRequestResponse;
import com.wotb.web.boost.entity.BoostRequest;
import com.wotb.web.boost.entity.BoostRequestAssignment;
import com.wotb.web.boost.entity.BoosterProfile;
import com.wotb.web.boost.enums.BoostAssignmentStatus;
import com.wotb.web.boost.enums.BoostRegion;
import com.wotb.web.boost.enums.BoostRequestStatus;
import com.wotb.web.boost.enums.BoostRequestType;
import com.wotb.web.boost.enums.ContactType;
import com.wotb.web.boost.repository.BoostRequestRepository;
import org.springframework.context.annotation.Profile;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.OffsetDateTime;
import java.util.List;
import java.util.Optional;
import java.util.Set;

/** 玩家侧需求服务。 */
@Service
@Profile("postgres")
public class BoostRequestService {

    private final BoostRequestRepository repository;
    private final BoostAssignmentService assignmentService;

    private static final Set<String> SENSITIVE_KEYWORDS = Set.of(
            "密码", "验证码", "账号密码", "登录密码", "password", "verification code"
    );

    public BoostRequestService(final BoostRequestRepository repository,
                               final BoostAssignmentService assignmentService) {
        this.repository = repository;
        this.assignmentService = assignmentService;
    }

    /** 创建陪练需求。 */
    @Transactional
    public CreateBoostRequestResponse create(final String requesterUserId,
                                             final String region,
                                             final String requestType,
                                             final String targetDescription,
                                             final String contactType,
                                             final String contactValue,
                                             final Long playerAccountId,
                                             final String playerNickname,
                                             final String budgetRange,
                                             final String availableTime,
                                             final String remark) {
        // 校验 region
        final String effectiveRegion = region != null ? region : "CN";
        BoostRegion.from(effectiveRegion);

        // 校验 requestType
        BoostRequestType.from(requestType);

        // 校验 contactType
        ContactType.from(contactType);

        // 敏感词检查
        checkSensitive(targetDescription);
        checkSensitive(remark);

        // 校验必填
        if (targetDescription == null || targetDescription.isBlank()) {
            throw new IllegalArgumentException("目标描述不能为空");
        }
        if (contactValue == null || contactValue.isBlank()) {
            throw new IllegalArgumentException("联系方式不能为空");
        }

        final BoostRequest req = new BoostRequest();
        req.setRequesterUserId(requesterUserId);
        req.setRegion(effectiveRegion.toUpperCase());
        req.setRequestType(requestType.toUpperCase());
        req.setTargetDescription(targetDescription.trim());
        req.setContactType(contactType.toUpperCase());
        req.setContactValue(contactValue.trim());
        req.setPlayerAccountId(playerAccountId);
        req.setPlayerNickname(playerNickname);
        req.setBudgetRange(budgetRange);
        req.setAvailableTime(availableTime);
        req.setRemark(remark);
        req.setStatus(BoostRequestStatus.NEW.name());

        repository.save(req);

        return new CreateBoostRequestResponse(
                req.getId(),
                req.getStatus(),
                "需求已提交，管理员会人工审核并联系你。",
                req.getCreatedAt()
        );
    }

    /** 查询当前用户的需求列表。 */
    public List<BoostRequestDto> listMy(final String requesterUserId) {
        return repository.findByRequesterUserIdOrderByCreatedAtDesc(requesterUserId)
                .stream()
                .map(this::toPlayerDto)
                .toList();
    }

    /** 查询当前用户单个需求。 */
    public Optional<BoostRequestDto> getMy(final Long id, final String requesterUserId) {
        return repository.findByIdAndRequesterUserId(id, requesterUserId)
                .map(this::toPlayerDto);
    }

    /** 取消自己的需求。 */
    @Transactional
    public BoostRequestDto cancel(final Long id, final String requesterUserId) {
        final BoostRequest req = repository.findByIdAndRequesterUserId(id, requesterUserId)
                .orElseThrow(() -> new IllegalArgumentException("REQUEST_NOT_FOUND"));

        final String currentStatus = req.getStatus().toUpperCase();
        if (!currentStatus.equals("NEW") && !currentStatus.equals("REVIEWING")) {
            throw new IllegalArgumentException("当前状态不允许取消");
        }

        req.setStatus(BoostRequestStatus.CANCELLED.name());
        req.setUpdatedAt(OffsetDateTime.now());
        repository.save(req);

        return toPlayerDto(req);
    }

    public BoostRequest getById(final Long id) {
        return repository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("REQUEST_NOT_FOUND"));
    }

    /** 转为玩家侧 DTO — 联系方式脱敏、不暴露 adminNote。 */
    BoostRequestDto toPlayerDto(final BoostRequest req) {
        final Optional<BoostRequestAssignment> active = assignmentService.findActive(req.getId());
        return new BoostRequestDto(
                req.getId(),
                req.getPlayerAccountId(),
                req.getPlayerNickname(),
                req.getRegion(),
                BoostRegion.from(req.getRegion()).label(),
                req.getRequestType(),
                BoostRequestType.from(req.getRequestType()).label(),
                req.getTargetDescription(),
                req.getBudgetRange(),
                req.getContactType(),
                maskContact(req.getContactValue()),
                req.getAvailableTime(),
                req.getRemark(),
                req.getStatus(),
                BoostRequestStatus.from(req.getStatus()).label(),
                active.isPresent(),
                req.getCreatedAt(),
                req.getUpdatedAt()
        );
    }

    /** 联系方式脱敏。 */
    static String maskContact(final String value) {
        if (value == null) { return null; }
        final int len = value.length();
        if (len <= 3) { return "***"; }
        if (len <= 7) {
            return value.charAt(0) + "***" + value.charAt(len - 1);
        }
        return value.substring(0, 3) + "****" + value.substring(len - 3);
    }

    static void checkSensitive(final String text) {
        if (text == null) { return; }
        final String lower = text.toLowerCase();
        for (final String kw : SENSITIVE_KEYWORDS) {
            if (lower.contains(kw)) {
                throw new IllegalArgumentException("SENSITIVE_INFO_NOT_ALLOWED");
            }
        }
    }
}

package com.wotb.web.controller;

import com.wotb.core.model.Battle;
import com.wotb.core.parse.ReplayParser;
import com.wotb.core.ref.Tankopedia;
import com.wotb.web.dto.LeaderboardRecordDto;
import com.wotb.web.service.LeaderboardService;
import org.springframework.context.annotation.Profile;
import org.springframework.web.bind.annotation.CrossOrigin;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import java.util.List;
import java.util.Map;

/**
 * 排行榜 REST API (仅 postgres profile; 只做 HTTP 映射, 业务在 LeaderboardService)。
 */
@RestController
@RequestMapping("/api/leaderboard")
@CrossOrigin(origins = "*")
@Profile("postgres")
public class LeaderboardController {

    private final LeaderboardService service;
    private final Tankopedia tankopedia = Tankopedia.load();

    public LeaderboardController(final LeaderboardService service) {
        this.service = service;
    }

    /** 上传单场回放，写入排行榜。 */
    @PostMapping("/upload")
    public Map<String, Object> upload(@RequestParam(name = "file") final MultipartFile file) throws Exception {
        final Battle battle = ReplayParser.parse(file.getBytes());
        final boolean saved = service.recordRecorder(battle, tankopedia);
        if (!saved) {
            return Map.of("status", "skipped",
                "arenaId", battle.arenaId,
                "reason", battle.arenaBonusType == null || battle.arenaBonusType != 1
                    ? "仅支持随机战斗" : "已存在或无法识别录像者");
        }
        return Map.of("status", "ok", "arenaId", battle.arenaId);
    }

    /** 全局伤害榜。 */
    @GetMapping("/top-damage")
    public List<LeaderboardRecordDto> topDamage(
            @RequestParam(name = "limit", defaultValue = "50") final int limit) {
        return service.topDamage(limit);
    }

    /** 指定车辆的伤害榜。 */
    @GetMapping("/tanks/{tankId}/top-damage")
    public List<LeaderboardRecordDto> topDamageByTank(
            @PathVariable final long tankId,
            @RequestParam(name = "limit", defaultValue = "50") final int limit) {
        return service.topDamageByTank(tankId, limit);
    }
}

package com.wotb.web.service;

import com.wotb.core.model.Battle;
import com.wotb.core.model.PlayerResult;
import com.wotb.core.ref.Tankopedia;
import com.wotb.web.dto.LeaderboardRecordDto;
import com.wotb.web.entity.LeaderboardRecord;
import com.wotb.web.repository.LeaderboardRecordRepository;
import org.springframework.context.annotation.Profile;
import org.springframework.dao.DataIntegrityViolationException;
import org.springframework.data.domain.PageRequest;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.time.OffsetDateTime;
import java.time.ZoneOffset;
import java.util.List;

/**
 * 排行榜业务 (仅 postgres profile)。MVP 只记录录像者本人单场成绩, 不存全场 14 人,
 * 不存 replay 原文件。默认/离线 profile 无此 bean, 由 ReplayService 经 ObjectProvider 可选调用。
 */
@Service
@Profile("postgres")
public class LeaderboardService {

    private static final int MAX_LIMIT = 200;
    private static final int DEFAULT_LIMIT = 50;
    /**
     * 排行榜只收随机战斗 (meta.json#arenaBonusType==1); 训练房(==2)/娱乐/联赛等一律拒绝。
     * 取值经真实样本核实: 1=随机, 2=训练房 (docs/replay-data.md 旧表的 "2=随机" 系误标)。
     */
    private static final int BATTLE_TYPE = 1;

    private final LeaderboardRecordRepository repository;

    public LeaderboardService(final LeaderboardRecordRepository repository) {
        this.repository = repository;
    }

    /**
     * 记录某场战斗中录像者本人的成绩 (best-effort)。
     * 仅随机战斗 (arenaBonusType==1) 计入; 训练房(2)/娱乐/联赛等拒绝。
     * meta 无录像者 accountId, 故按昵称在 players 中匹配 battle.recorder; 匹配不到则跳过。
     * 已存在 (arena_id, account_id) 则不重复插入。
     */
    public boolean recordRecorder(final Battle battle, final Tankopedia tankopedia) {
        if (battle == null || battle.arenaId == null) {
            return false;
        }
        if (battle.arenaBonusType == null || battle.arenaBonusType != BATTLE_TYPE) {
            return false;
        }
        final PlayerResult recorder = battle.recorderResult();
        if (recorder == null) {
            return false;
        }
        if (repository.findByArenaIdAndAccountId(battle.arenaId, recorder.accountId).isPresent()) {
            return false;
        }
        final LeaderboardRecord record = new LeaderboardRecord();
        record.setArenaId(battle.arenaId);
        record.setAccountId(recorder.accountId);
        record.setNickname(recorder.nickname);
        record.setTankId(recorder.tankId);
        record.setTankName(tankopedia.info(recorder.tankId).name());
        record.setDamageDealt(recorder.damageDealt);
        record.setMapName(battle.mapName);
        record.setVersion(battle.version != null && !battle.version.isEmpty() ? battle.version : null);
        // 过滤无效时间戳: 0 或早于 WoT Blitz 发布 (2014); 兼容秒级/毫秒级 epoch。
        if (battle.startTime != null) {
            final long epochSeconds = battle.startTime > 100_000_000_000L
                    ? battle.startTime / 1000L : battle.startTime;
            if (epochSeconds > 1_388_534_400L) {
                record.setBattleTime(OffsetDateTime.ofInstant(
                        Instant.ofEpochSecond(epochSeconds), ZoneOffset.UTC));
            }
        }
        try {
            repository.save(record);
            return true;
        } catch (final DataIntegrityViolationException ignored) {
            return false;
        }
    }

    /** 全局伤害榜 (降序)。 */
    public List<LeaderboardRecordDto> topDamage(final int limit) {
        return repository.findAllByOrderByDamageDealtDesc(PageRequest.of(0, clamp(limit)))
                .stream().map(LeaderboardService::toDto).toList();
    }

    /** 指定车辆的伤害榜 (降序)。 */
    public List<LeaderboardRecordDto> topDamageByTank(final long tankId, final int limit) {
        return repository.findByTankIdOrderByDamageDealtDesc(tankId, PageRequest.of(0, clamp(limit)))
                .stream().map(LeaderboardService::toDto).toList();
    }

    private static int clamp(final int limit) {
        if (limit <= 0) {
            return DEFAULT_LIMIT;
        }
        return Math.min(limit, MAX_LIMIT);
    }

    private static LeaderboardRecordDto toDto(final LeaderboardRecord r) {
        return new LeaderboardRecordDto(r.getId(), r.getArenaId(), r.getTankId(), r.getTankName(),
                r.getAccountId(), r.getNickname(), r.getDamageDealt(), r.getMapName(),
                r.getVersion(), r.getBattleTime(), r.getCreatedAt());
    }
}

